class Complex {
private:
 double real, imag;
public:
 Complex() : real(0), imag(0) {}
 Complex(double r, double i) : real(r), imag(i) {}

 // Member function for + operator
 Complex operator+(const Complex& obj) const {
 return Complex(real + obj.real, imag + obj.imag);
 }

 // Friend function for << operator
 friend ostream& operator<<(ostream& os, const Complex& c) {
 os << c.real << " + " << c.imag << "i";
 return os;
 }
};

int main() {
 Complex c1(3, 4), c2(1, 2), c3;
 c3 = c1 + c2; // Uses operator+
 cout << c3; // Uses operator<<
 return 0;
}

class Counter {
private:
 int value;
public:
 Counter(int v = 0) : value(v) {}

 // Prefix increment - returns reference
 Counter& operator++() {
 ++value;
 return *this; // Returns current object
 }

 // Postfix increment - returns copy (value)
 Counter operator++(int) {
 Counter temp = *this; // Save current state
 ++value; // Increment
 return temp; // Return old value
 }

 int getValue() const { return value; }
};

int main() {
 Counter c1(5), c2(5);
 ++c1; // c1.value = 6
 c2++; // c2.value = 6, but expression returns old value
 return 0;
}

class String {
private:
 char* str;
 int length;
public:
 String(const char* s) {
 length = strlen(s);
 str = new char[length + 1];
 strcpy(str, s);
 }

 // Copy constructor (important for deep copy)
 String(const String& s) {
 length = s.length;
 str = new char[length + 1];
 strcpy(str, s.str);
 }

 // Assignment operator with self-assignment check
 String& operator=(const String& s) {
 if (this != &s) { // Self-assignment check
 delete[] str; // Free existing memory
 length = s.length;
 str = new char[length + 1];
 strcpy(str, s.str);
 }
 return *this; // Enable chaining
 }

 ~String() { delete[] str; }
};

int main() {
 String s1("Hello"), s2("World");
 s1 = s1; // Self-assignment (should work correctly)
 s2 = s1; // Normal assignment
 return 0;
}

class Array {
private:
 int* arr;
 int size;
public:
 Array(int s) : size(s) {
 arr = new int[size]();
 }

 // Non-const version for modification
 int& operator[](int index) {
 if (index < 0 || index >= size) {
 throw out_of_range("Index out of bounds");
 }
 return arr[index];
 }

 // Const version for read-only access
 const int& operator[](int index) const {
 if (index < 0 || index >= size) {
 throw out_of_range("Index out of bounds");
 }
 return arr[index];
 }

 ~Array() { delete[] arr; }
};

int main() {
 Array a(5);
 a[0] = 10; // Uses non-const version
 a[1] = 20;
 cout << a[0]; // Uses const version
 return 0;
}

class Fraction {
private:
 int num, den;
public:
 Fraction(int n, int d) : num(n), den(d) {}

 // Conversion operator to double
 operator double() const {
 return static_cast<double>(num) / den;
 }

 // Conversion operator to int
 operator int() const {
 return num / den; // Truncates
 }

 void display() const {
 cout << num << "/" << den << endl;
 }
};

int main() {
 Fraction f(5, 2); // Represents 5/2 = 2.5
 double d = f; // Implicit conversion to double
 int i = f; // Implicit conversion to int (2)
 cout << d << endl; // Prints 2.5
 cout << i << endl; // Prints 2
 return 0;
}

class Adder {
private:
 int increment;
public:
 Adder(int inc) : increment(inc) {}

 // Overloaded function call operator
 int operator()(int value) const {
 return value + increment;
 }
};

int main() {
 Adder add5(5);
 Adder add10(10);

 cout << add5(10) << endl; // 15
 cout << add10(10) << endl; // 20
 cout << add5(100) << endl; // 105

 return 0;
}
